class Solution:
    def minimizeStringValue(self, s: str) -> str:
        n = len(s)
        res = []
        for c in s:
            if c == '?':
                res.append(min(set('abcdefghijklmnopqrstuvwxyz') - set(res)))
            else:
                res.append(c)
        return ''.join(res)
